-- ============================================================
-- Dashboard KPI view — replaces JS aggregation in buildStatusData()
-- ============================================================

CREATE OR REPLACE VIEW dashboard_kpis AS
SELECT
  inspector_id,
  COUNT(*)                                                                          AS total_inspections,
  COUNT(*) FILTER (WHERE created_at > NOW() - INTERVAL '30 days')                  AS recent_inspections,
  COUNT(*) FILTER (WHERE status = 'submitted')                                      AS submitted_inspections,
  COUNT(*) FILTER (WHERE status IN ('draft', 'in_progress'))                        AS in_progress_inspections,
  COUNT(*) FILTER (WHERE approval_status = 'approved')                              AS approved_count,
  COUNT(*) FILTER (WHERE approval_status = 'approved_with_recommendations')         AS approved_with_recs_count,
  COUNT(*) FILTER (WHERE approval_status = 'rejected')                              AS rejected_count
FROM inspections
GROUP BY inspector_id;

-- RLS: inspectors can only see their own KPI row
ALTER VIEW dashboard_kpis OWNER TO postgres;
